CREATE TABLE IF NOT EXISTS dados_semana (
    id            INTEGER PRIMARY KEY AUTOINCREMENT,
    aluno         TEXT NOT NULL,
    prescricao    TEXT,
    observacao    TEXT,
    dia           DATE NOT NULL,
    horario       TIME NOT NULL,
    turno         TEXT NOT NULL,
    check_in      TEXT DEFAULT 'pendente',
    data_criacao  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
